// @vitest-environment node
/**
 * SPEC-039: constancia de los desenlaces manuales de preguntas en la NOTA —
 * el prompt de generación incluye las secciones condicionales de preguntas
 * descartadas (con su motivo, o «sin motivo indicado») y marcadas respondidas
 * cuando la entrevista tiene questionOutcomes, y sin ellos es idéntico al
 * anterior (sin rastro de esas secciones).
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-017 (SDK de Anthropic mockeado con clases de error espejo,
 * dialog de electron mockeado, store/repository REALES sobre dir temporal).
 */
import { mkdtempSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import { generateInterviewNote } from '../../../src/main/noteService'
import type { Interview, NoteTemplate } from '../../../src/renderer/src/types/domain'

const harness = vi.hoisted(() => {
  /** Jerarquía espejo de la del SDK: instanceof debe funcionar en mapSdkError. */
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    showSaveDialog: vi.fn(),
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  dialog: {
    showSaveDialog: harness.showSaveDialog
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

/** Respuesta del SDK con bloque thinking + bloque text (el JSON va en text). */
function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

const GENERATED_SECTIONS = {
  sections: [
    { title: 'lo que diga la IA se ignora', contentMarkdown: 'El CTO gestiona todo a mano.' },
    { title: 'da igual', contentMarkdown: '«Nos lleva dos días cada registro»' }
  ]
}

let dataDir = ''

function writeTranscriptFile(): string {
  const dir = mkdtempSync(join(tmpdir(), 'maurya-note-outcomes-transcript-'))
  const transcriptPath = join(dir, 'entrevista.transcript.json')
  writeFileSync(
    transcriptPath,
    JSON.stringify({
      lines: [
        {
          channel: 'mic',
          speaker: 0,
          text: '¿Cómo gestionáis hoy el registro?',
          startMs: 0,
          endMs: 1000,
          receivedAtMs: 1100
        },
        {
          channel: 'system',
          speaker: 1,
          text: 'Todo a mano, nos lleva dos días.',
          startMs: 1000,
          endMs: 2000,
          receivedAtMs: 2100
        }
      ],
      latency: null,
      assistant: null
    })
  )
  return transcriptPath
}

function seedBase(): { interview: Interview; template: NoteTemplate } {
  const discovery = repository.createDiscovery({ name: 'Discovery Maurya' })
  const company = repository.createCompany({ name: 'Acme Corp' })
  const template = repository.createNoteTemplate({
    name: 'Notas discovery',
    context: 'Céntrate en dolores y evidencias.',
    sections: [
      { title: 'Dolores', description: 'Problemas detectados' },
      { title: 'Citas', description: 'Frases literales relevantes' }
    ]
  })
  const interview = repository.createInterview({
    discoveryId: discovery.id,
    companyId: company.id,
    title: 'Discovery con Acme'
  })
  repository.updateInterview(interview.id, {
    transcriptPath: writeTranscriptFile(),
    status: 'recorded'
  })
  return { interview: repository.getInterview(interview.id), template }
}

function userPrompt(): string {
  const params = harness.create.mock.calls[0][0] as {
    messages: Array<{ content: string }>
  }
  return params.messages[0].content
}

beforeEach(() => {
  vi.clearAllMocks()
  dataDir = mkdtempSync(join(tmpdir(), 'maurya-note-outcomes-'))
  initStore(dataDir)
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
})

afterEach(() => {
  delete process.env['ANTHROPIC_API_KEY']
})

describe('noteService (questionOutcomes SPEC-039)', () => {
  // SPEC-039 · AC-20 (nota: secciones de descartadas con motivo y de respondidas)
  it('includes the discarded questions with their reasons and the answered questions as prompt sections when the interview has questionOutcomes', async () => {
    const { interview, template } = seedBase()
    // Camino real de recording:stop + guardado de motivos: main escribe outcomes
    repository.setInterviewQuestionOutcomes(interview.id, [
      {
        question: '¿Cuándo fue la última vez que pasó?',
        outcome: 'discarded',
        reason: 'Ya lo había contado al principio'
      },
      { question: '¿Cuánto pagasteis por la solución actual?', outcome: 'discarded' },
      { question: '¿Quién decidió la compra?', outcome: 'answered' }
    ])
    harness.create.mockResolvedValue(sdkResponse(GENERATED_SECTIONS))

    await generateInterviewNote(interview.id, template.id)

    const prompt = userPrompt()
    expect(prompt).toContain(
      '## Preguntas descartadas por el entrevistador (con su motivo)\n' +
        '- ¿Cuándo fue la última vez que pasó? — Motivo: Ya lo había contado al principio\n' +
        '- ¿Cuánto pagasteis por la solución actual? — Motivo: sin motivo indicado'
    )
    expect(prompt).toContain(
      '## Preguntas ya respondidas marcadas por el entrevistador\n- ¿Quién decidió la compra?'
    )
  })

  // SPEC-039 · AC-21 (nota sin questionOutcomes: prompt idéntico al actual)
  it('omits both sections when the interview has no questionOutcomes keeping the prompt identical', async () => {
    const { interview, template } = seedBase()
    harness.create.mockResolvedValue(sdkResponse(GENERATED_SECTIONS))

    await generateInterviewNote(interview.id, template.id)

    const prompt = userPrompt()
    expect(prompt).not.toContain('Preguntas descartadas por el entrevistador')
    expect(prompt).not.toContain('Preguntas ya respondidas marcadas por el entrevistador')
    // El resto del prompt conserva su forma (secciones existentes intactas)
    expect(prompt).toContain('## Empresa\nNombre: Acme Corp')
    expect(prompt).toContain('## Conversación')
    expect(prompt).toContain(
      '## Tarea\nGenera la nota de resumen de la entrevista "Discovery con Acme"'
    )
  })
})
